package com.example.eventstreamingplatform;

import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.UUID;

@Service
public class EventProducerService {

    private static final String TOPIC = "event-stream-topic";
    private final KafkaTemplate<String, EventMessage> kafkaTemplate;

    public EventProducerService(KafkaTemplate<String, EventMessage> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public void publishEvent(String eventType, String payload) {
        EventMessage message = new EventMessage(
                UUID.randomUUID().toString(),
                eventType,
                payload,
                Instant.now()
        );
        kafkaTemplate.send(TOPIC, message.getEventId(), message);
    }
}

package com.example.eventstreamingplatform;

import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Service;

@Service
public class EventConsumerService {

    @KafkaListener(topics = "event-stream-topic", groupId = "event-streaming-platform-group")
    public void consume(EventMessage message) {
        System.out.println("Consumed event: " + message.getEventId()
                + ", type: " + message.getEventType()
                + ", payload: " + message.getPayload()
                + ", createdAt: " + message.getCreatedAt());
    }
}

package com.example.eventstreamingplatform;

import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.Map;

@RestController
@RequestMapping("/events")
public class EventController {

    private final EventProducerService eventProducerService;

    public EventController(EventProducerService eventProducerService) {
        this.eventProducerService = eventProducerService;
    }

    @PostMapping
    public ResponseEntity<Map<String, String>> publishEvent(@RequestBody EventRequest request) {
        eventProducerService.publishEvent(request.getEventType(), request.getPayload());
        return ResponseEntity.ok(Map.of("status", "published"));
    }
}

